\begin{lessonbox}
This lesson focuses on Algebraic Expressions: Problem-Solving Intensive.
\end{lessonbox}

\section*{Course Information}
\noindent \textbf{Course:} MATH095 - Introductory Mathematics \\
\textbf{Week:} 2 \\
\textbf{Lesson:} 2 \\
\textbf{Instructor:} Michael Reid \\
\textbf{Department:} Mathematics and Engineering \\
\textbf{Date:} May 19, 2026 \\
\textbf{Duration:} 75 minutes \\
\textbf{Lesson Type:} Problem-solving

\section*{Learning Outcomes}
\begin{samepage}
\needspace{8\baselineskip}
\begin{itemize}
    \item \textbf{LO1:} Simplify algebraic expressions by combining like terms with accuracy, demonstrating mastery of coefficient arithmetic and variable identification.
    \item \textbf{LO2:} Apply the distributive property to expand algebraic expressions involving single and multiple terms, correctly handling negative signs and fractional coefficients.
    \item \textbf{LO3:} Evaluate algebraic expressions by substituting given numerical values for variables and computing the result using correct order of operations.
    \item \textbf{LO4:} Translate verbal descriptions of quantities and relationships into equivalent algebraic expressions, demonstrating understanding of mathematical vocabulary and structure.
\end{itemize}
\end{samepage}

\section*{Prerequisites}
\begin{samepage}
\needspace{8\baselineskip}
\begin{itemize}
    \item \textbf{Order of Operations (PEMDAS/BODMAS):} Students must be able to evaluate numerical expressions following the standard order of operations.
    \item \textbf{Integer Arithmetic:} Proficiency with adding, subtracting, multiplying, and dividing positive and negative integers is essential.
    \item \textbf{Fraction Operations:} Students should be able to add, subtract, multiply, and divide fractions, including finding common denominators and simplifying results.
    \item \textbf{Basic Exponent Rules:} Understanding that $x^2$ means $x \times x$ and $x^3$ means $x \times x \times x$ is required.
    \item \textbf{Variables as Placeholders:} Students must understand that letters like $x$, $y$, and $n$ represent unknown or variable quantities.
    \item \textbf{Components of Algebraic Terms:} Students should be able to identify the coefficient, variable(s), and exponent in a term.
\end{itemize}
\end{samepage}

\section*{Key Terms}
\begin{samepage}
\needspace{8\baselineskip}
\begin{itemize}
    \item \textbf{Like Terms:} Like terms are algebraic terms that have exactly the same variable parts. For example, $3x^2$ and $-7x^2$ are like terms.
    \item \textbf{Coefficient:} The coefficient is the numerical factor that multiplies a variable in an algebraic term.
    \item \textbf{Distributive Property:} The distributive property states that multiplication distributes over addition and subtraction.
    \item \textbf{Constant Term:} A constant term is a term in an algebraic expression that contains no variables.
    \item \textbf{Algebraic Expression:} An algebraic expression is a mathematical phrase that combines numbers, variables, and operation symbols.
    \item \textbf{Substitution:} Substitution is the process of replacing a variable in an algebraic expression with a specific numerical value.
    \item \textbf{Term:} A term is a single mathematical entity within an algebraic expression.
    \item \textbf{Simplify:} To simplify an algebraic expression means to rewrite it in its most compact or reduced form.
\end{itemize}
\end{samepage}

\section*{Key Formulas}
\begin{samepage}
\needspace{8\baselineskip}
\begin{itemize}
    \item \textbf{Combining Like Terms:} $ax^n + bx^n = (a + b)x^n$
    \item \textbf{Distributive Property (Expansion):} $a(b + c) = ab + ac$
    \item \textbf{Negative Distribution:} $-(a + b) = -a - b$
    \item \textbf{Double Distribution (FOIL for Binomials):} $(a + b)(c + d) = ac + ad + bc + bd$
    \item \textbf{Substitution Evaluation:} $E(x)\big|_{x=a} = E(a)$
\end{itemize}
\end{samepage}

\section*{Technique Overview}
This problem-solving session focuses on developing systematic approaches to manipulating algebraic expressions—a foundational skill that underpins virtually all subsequent work in algebra, calculus, and applied mathematics.

\begin{itemize}
    \item \textbf{Technique 1: Systematic Like-Term Identification.} Develop the habit of marking or grouping like terms visually.
    \item \textbf{Technique 2: Distribution with Sign Tracking.} Write out each multiplication separately before combining.
    \item \textbf{Technique 3: Substitution with Parenthetical Protection.} Always enclose the substituted value in parentheses.
    \item \textbf{Technique 4: Translation via Key Phrases.} Identify key phrases and their mathematical equivalents.
    \item \textbf{Technique 5: Verification by Back-Substitution.} Verify your work by substituting a simple test value.
\end{itemize}

\section*{Worked Examples}
\begin{samepage}
\begin{examplebox}{Worked Example 1: Combining Like Terms with Integers}
Simplify the algebraic expression $7x + 3 - 2x + 8 - 5x + 1$ by combining all like terms. Express your answer in standard form with the variable term first, followed by the constant.

\textbf{Given Information:}
\begin{itemize}
    \item Expression: $7x + 3 - 2x + 8 - 5x + 1$
    \item Terms with variable $x$: $7x$, $-2x$, $-5x$
    \item Constant terms: $3$, $8$, $1$
\end{itemize}

\textbf{Required:} Simplified expression with like terms combined.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Identify and group like terms:} 
    \begin{align*}
    7x + 3 - 2x + 8 - 5x + 1 \&= (7x - 2x - 5x) + (3 + 8 + 1)
    \end{align*}
    \item \textbf{Combine the coefficients of $x$-terms:} 
    \begin{align*}
    7 + (-2) + (-5) \&= 0 \quad \Rightarrow \quad (7x - 2x - 5x) = 0x = 0
    \end{align*}
    \item \textbf{Combine the constant terms:} 
    \begin{align*}
    3 + 8 + 1 \&= 12
    \end{align*}
    \item \textbf{Write the simplified expression:} 
    \begin{align*}
    0 + 12 \&= 12
    \end{align*}
    \item \textbf{Verify by substitution:} 
    \begin{align*}
    \text{Original at } x=2: \quad 7(2) + 3 - 2(2) + 8 - 5(2) + 1 \&= 12 \quad \text{✓ Matches simplified answer}
    \end{align*}
\end{enumerate}

\textbf{Final Answer:} $\boxed{12}$. The expression simplifies to the constant 12, meaning the variable terms completely cancel out.

\textbf{Teaching Notes:} This example demonstrates that variable terms can sum to zero, leaving only a constant. Emphasize that this is a valid and common outcome.
\end{examplebox}
\begin{solutionbox}
\textbf{Solution to Worked Example 1:} The steps outlined above lead to the final answer of 12, confirming the simplification process.
\end{solutionbox}
\end{samepage}

\begin{samepage}
\begin{examplebox}{Worked Example 2: Combining Like Terms with Negative Coefficients}
Simplify the expression $-4a^2 + 6a - 9 + 2a^2 - 3a + 5$ by identifying and combining all like terms. Present your final answer in descending order of powers.

\textbf{Given Information:}
\begin{itemize}
    \item Expression: $-4a^2 + 6a - 9 + 2a^2 - 3a + 5$
    \item $a^2$ terms: $-4a^2$ and $2a^2$
    \item $a$ terms: $6a$ and $-3a$
    \item Constant terms: $-9$ and $5$
\end{itemize}

\textbf{Required:} Simplified polynomial in descending order of powers.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Identify all terms and their types:} 
    \begin{align*}
    a^2 \text{ terms: } -4a^2, 2a^2; \quad a \text{ terms: } 6a, -3a; \quad \text{constants: } -9, 5
    \end{align*}
    \item \textbf{Combine the $a^2$ terms:} 
    \begin{align*}
    (-4)a^2 + 2a^2 \&= (-4 + 2)a^2 \quad \Rightarrow \quad -2a^2
    \end{align*}
    \item \textbf{Combine the $a$ terms:} 
    \begin{align*}
    6a + (-3a) \&= (6 - 3)a \quad \Rightarrow \quad 3a
    \end{align*}
    \item \textbf{Combine the constant terms:} 
    \begin{align*}
    -9 + 5 \&= -4
    \end{align*}
    \item \textbf{Write the final simplified expression:} 
    \begin{align*}
    -2a^2 + 3a - 4
    \end{align*}
    \item \textbf{Verify by substitution with } $a = 1$: 
    \begin{align*}
    \text{Original: } -4(1)^2 + 6(1) - 9 + 2(1)^2 - 3(1) + 5 \&= -3 \quad \text{✓}
    \end{align*}
\end{enumerate}

\textbf{Final Answer:} $\boxed{-2a^2 + 3a - 4}$. The polynomial has three terms in descending order of degree.

\textbf{Teaching Notes:} This example reinforces proper handling of negative coefficients. Remind students that $-4 + 2 = -2$, not $-6$.
\end{examplebox}
\begin{solutionbox}
\textbf{Solution to Worked Example 2:} The steps outlined above lead to the final answer of $-2a^2 + 3a - 4$, confirming the simplification process.
\end{solutionbox}
\end{samepage}

\begin{samepage}
\begin{examplebox}{Worked Example 3: Applying the Distributive Property}
Expand and simplify the expression $4(2x - 3) - 2(x + 5)$ using the distributive property. Show all distribution steps explicitly before combining like terms.

\textbf{Given Information:}
\begin{itemize}
    \item Expression: $4(2x - 3) - 2(x + 5)$
    \item First distribution: $4$ multiplies $(2x - 3)$
    \item Second distribution: $-2$ multiplies $(x + 5)$
\end{itemize}

\textbf{Required:} Fully expanded and simplified expression.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Distribute } $4$ \textbf{ across } $(2x - 3)$: 
    \begin{align*}
    4(2x - 3) \&= 8x - 12
    \end{align*}
    \item \textbf{Distribute } $-2$ \textbf{ across } $(x + 5)$: 
    \begin{align*}
    -2(x + 5) \&= -2x - 10
    \end{align*}
    \item \textbf{Write the expanded expression:} 
    \begin{align*}
    8x - 12 - 2x - 10
    \end{align*}
    \item \textbf{Group like terms:} 
    \begin{align*}
    (8x - 2x) + (-12 - 10) \&= 6x - 22
    \end{align*}
    \item \textbf{Verify with } $x = 3$: 
    \begin{align*}
    \text{Original: } 4(2(3) - 3) - 2(3 + 5) \&= -4 \quad \text{✓}
    \end{align*}
\end{enumerate}

\textbf{Final Answer:} $\boxed{6x - 22}$. The expression consists of a variable term and a constant term.

\textbf{Teaching Notes:} Encourage writing out $(-2)(x) + (-2)(5)$ explicitly to track signs.
\end{examplebox}
\begin{solutionbox}
\textbf{Solution to Worked Example 3:} The steps outlined above lead to the final answer of $6x - 22$, confirming the simplification process.
\end{solutionbox}
\end{samepage}

\begin{samepage}
\begin{examplebox}{Worked Example 4: Nested Distribution with Multiple Parentheses}
Simplify the expression $3[2(x + 4) - 5(x - 1)]$ by working from the innermost parentheses outward. Show each distribution step and combine all like terms.

\textbf{Given Information:}
\begin{itemize}
    \item Expression: $3[2(x + 4) - 5(x - 1)]$
    \item Inner distributions: $2(x + 4)$ and $5(x - 1)$
    \item Outer multiplier: $3$
\end{itemize}

\textbf{Required:} Fully simplified expression.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Distribute } $2$ \textbf{ across } $(x + 4)$: 
    \begin{align*}
    2(x + 4) \&= 2x + 8
    \end{align*}
    \item \textbf{Distribute } $5$ \textbf{ across } $(x - 1)$: 
    \begin{align*}
    5(x - 1) \&= 5x - 5
    \end{align*}
    \item \textbf{Substitute expansions into the bracket:} 
    \begin{align*}
    3[2(x + 4) - 5(x - 1)] \&= 3[(2x + 8) - (5x - 5)]
    \end{align*}
    \item \textbf{Combine like terms inside the bracket:} 
    \begin{align*}
    (2x - 5x) + (8 + 5) \&= -3x + 13
    \end{align*}
    \item \textbf{Distribute } $3$ \textbf{ across the simplified bracket contents:} 
    \begin{align*}
    3(-3x + 13) \&= -9x + 39
    \end{align*}
    \item \textbf{Verify with } $x = 2$: 
    \begin{align*}
    \text{Original: } 3[2(2 + 4) - 5(2 - 1)] \&= 21 \quad \text{✓}
    \end{align*}
\end{enumerate}

\textbf{Final Answer:} $\boxed{-9x + 39}$ or equivalently $\boxed{39 - 9x}$.

\textbf{Teaching Notes:} Working inside-out systematically prevents confusion.
\end{examplebox}
\begin{solutionbox}
\textbf{Solution to Worked Example 4:} The steps outlined above lead to the final answer of $-9x + 39$, confirming the simplification process.
\end{solutionbox}
\end{samepage}

\begin{samepage}
\begin{examplebox}{Worked Example 5: Evaluating Expressions with Negative Substitution}
Evaluate the expression $2x^3 - 5x^2 + 3x - 7$ when $x = -2$. Show each substitution with proper parentheses and follow the order of operations.

\textbf{Given Information:}
\begin{itemize}
    \item Expression: $2x^3 - 5x^2 + 3x - 7$
    \item Value: $x = -2$
\end{itemize}

\textbf{Required:} Evaluated expression.

\textbf{Solution Steps:}
\begin{enumerate}
    \item Substitute $x = -2$ into the expression:
    \begin{align*}
    2(-2)^3 - 5(-2)^2 + 3(-2) - 7
    \end{align*}
    \item Calculate each term:
    \begin{align*}
    2(-8) - 5(4) - 6 - 7 \&= -16 - 20 - 6 - 7
    \end{align*}
    \item Combine the results:
    \begin{align*}
    -16 - 20 - 6 - 7 \&= -49
    \end{align*}
\end{enumerate}

\textbf{Final Answer:} $\boxed{-49}$.

\textbf{Teaching Notes:} Emphasize the importance of using parentheses when substituting negative values to avoid sign errors.
\end{examplebox}
\begin{solutionbox}
\textbf{Solution to Worked Example 5:} The steps outlined above lead to the final answer of $-49$, confirming the evaluation process.
\end{solutionbox}
\end{samepage}

